function checkStrings() {
	if (typeof window === "undefined") return true;
	const l = location.hostname;
	const t = [
		// svar.dev
		"c3Zhci5kZXY=",
		// dhtmlx.com
		"ZGh0bWx4LmNvbQ==",
		// dhtmlxcode.com
		"ZGh0bWx4Y29kZS5jb20=",
		// webixcode.com
		"d2ViaXhjb2RlLmNvbQ==",
		// webix.io
		"d2ViaXguaW8=",
		// repl.co
		"cmVwbC5jbw==",
		// csb.app
		"Y3NiLmFwcA==",
		// replit.dev
		"cmVwbGl0LmRldg==",
	];

	for (let i = 0; i < t.length; i++) {
		const x = window.atob(t[i]);
		if (x === l || l.endsWith("." + x)) return true;
	}

	return false;
}

const amode = checkStrings();

export function isValid() {
	return amode;
}

export function isExpired() {
	return new Date().valueOf() > 0x00ffffff * 256000;
}

export function isBadLuck() {
	return Math.random() < 0.05;
}
